using UnityEditor;
using System.Collections.Generic;
using System.IO;

public class FBXChecker
{
    public static string Run()
    {
        string[] guids = AssetDatabase.FindAssets("t:Model");
        List<string> issues = new List<string>();
        foreach (string guid in guids)
        {
            string path = AssetDatabase.GUIDToAssetPath(guid);
            if (path.EndsWith(".fbx", System.StringComparison.OrdinalIgnoreCase))
            {
                ModelImporter importer = AssetImporter.GetAtPath(path) as ModelImporter;
                if (importer != null)
                {
                    if (!string.IsNullOrEmpty(importer.animationImportWarnings))
                    {
                        issues.Add($"{path}: {importer.animationImportWarnings}");
                    }
                    if (!string.IsNullOrEmpty(importer.animationImportErrors))
                    {
                        if (importer.animationImportErrors.Contains("Framerate was set to 0.00")) {
                             issues.Add($"{path}: MATCHED ERROR: {importer.animationImportErrors}");
                        } else {
                             issues.Add($"{path}: ERROR: {importer.animationImportErrors}");
                        }
                    }
                }
            }
        }
        return issues.Count > 0 ? string.Join("\n", issues) : "No issues found in importer warnings/errors.";
    }
}
